import {
  Transaction,
  CategoryGroup,
  DuplicateGroup,
  RunningBalanceEntry,
  SpenderSummary,
  PipelineResult,
} from "./types.js";

/**
 * Groups transactions by category and calculates totals.
 * O(n) using a Map instead of linear scans + reduce.
 */
export function groupByCategory(transactions: Transaction[]): CategoryGroup[] {
  const map = new Map<string, CategoryGroup>();

  for (const transaction of transactions) {
    const group = map.get(transaction.category);
    if (group) {
      group.transactions.push(transaction);
      group.total += transaction.amount;
    } else {
      map.set(transaction.category, {
        category: transaction.category,
        transactions: [transaction],
        total: transaction.amount,
      });
    }
  }

  return Array.from(map.values());
}

/**
 * Finds duplicate transactions (same userId + amount + date).
 * O(n) using a Map keyed by composite string instead of O(n^2) pair comparison.
 */
export function findDuplicates(transactions: Transaction[]): DuplicateGroup[] {
  const map = new Map<string, DuplicateGroup>();

  for (const transaction of transactions) {
    const key = `${transaction.userId}|${transaction.amount}|${transaction.date}`;
    const group = map.get(key);
    if (group) {
      group.transactions.push(transaction);
    } else {
      map.set(key, { key, transactions: [transaction] });
    }
  }

  // Only return groups that have more than one transaction (actual duplicates)
  return Array.from(map.values()).filter((g) => g.transactions.length > 1);
}

/**
 * Calculates running balance for a specific user, sorted by date.
 * O(n log n) — filter once, sort once, single accumulation pass.
 */
export function calculateRunningBalance(
  transactions: Transaction[],
  userId: string
): RunningBalanceEntry[] {
  const userTransactions = transactions
    .filter((t) => t.userId === userId)
    .sort((a, b) => a.date.localeCompare(b.date));

  let balance = 0;
  const entries: RunningBalanceEntry[] = [];

  for (const t of userTransactions) {
    balance += t.amount;
    entries.push({
      transactionId: t.id,
      amount: t.amount,
      balance: Math.round(balance * 100) / 100,
      date: t.date,
    });
  }

  return entries;
}

/**
 * Returns the top N spenders.
 * O(n + u log u) — single pass aggregation with a Map, then sort.
 */
export function topSpenders(
  transactions: Transaction[],
  n: number
): SpenderSummary[] {
  const map = new Map<string, SpenderSummary>();

  for (const t of transactions) {
    const summary = map.get(t.userId);
    if (summary) {
      summary.totalSpent += t.amount;
      summary.transactionCount++;
    } else {
      map.set(t.userId, {
        userId: t.userId,
        totalSpent: t.amount,
        transactionCount: 1,
      });
    }
  }

  const summaries = Array.from(map.values());

  // Round totals
  for (const s of summaries) {
    s.totalSpent = Math.round(s.totalSpent * 100) / 100;
  }

  summaries.sort((a, b) => b.totalSpent - a.totalSpent);

  return summaries.slice(0, n);
}

/**
 * Searches transactions by description text.
 * Compiles the RegExp once and relies on unique IDs to skip dedup scan.
 */
export function searchTransactions(
  transactions: Transaction[],
  query: string
): Transaction[] {
  const pattern = new RegExp(
    query.replace(/[.*+?^${}()|[\]\\]/g, "\\$&"),
    "i"
  );

  return transactions.filter((t) => pattern.test(t.description));
}

/**
 * Runs the full processing pipeline.
 */
export function processAll(
  transactions: Transaction[],
  topN: number = 10
): PipelineResult {
  const categoryGroups = groupByCategory(transactions);
  const duplicates = findDuplicates(transactions);
  const topSpendersList = topSpenders(transactions, topN);

  return {
    categoryGroups,
    duplicates,
    topSpenders: topSpendersList,
  };
}

